import pandas as pd
import os
import glob
import numpy as np

def process_csv_directory(directory_path, list_of_indices, target_step=498):
    """
    directory_path: CSV 所在目录
    list_of_indices: 包含多个 list 的 list
    target_step: 成功的阈值步数
    """
    
    # 1. 取所有传入 list 的交集
    if not list_of_indices:
        print("Error: No lists provided.")
        return
    
    sets = [set(lst) for lst in list_of_indices]
    intersection_set = set.intersection(*sets)
    selected_indices = sorted(list(intersection_set))
    
    print(f"Intersection of {len(list_of_indices)} lists. Length: {len(selected_indices)}")

    # 定义映射关系：{ 打印显示的名称 : CSV中实际的列名 }
    # 请根据你 CSV 的实际表头修改右侧的字符串
    column_mapping = {
        "AnchorPosError": "error_anchor_pos",
        "AnchorLinVel": "error_anchor_lin_vel",
        "BodyLinVel": "error_body_lin_vel",
        "JointVel": "error_joint_vel",
        "JointPos": "error_joint_pos"
    }

    csv_files = glob.glob(os.path.join(directory_path, "*.csv"))
    if not csv_files:
        print(f"No CSV files found in {directory_path}")
        return

    for file_path in csv_files:
        filename = os.path.basename(file_path)
        try:
            df = pd.read_csv(file_path)
            df['step'] = pd.to_numeric(df['step'], errors='coerce')
            df = df.dropna(subset=['step']).reset_index(drop=True) 
            
            if df.empty:
                continue

            total_rows = len(df)

            # --- 1. 全量计算 (Global) ---
            success_mask_all = df['step'] >= target_step
            success_rows = success_mask_all.sum()
            global_success_rate = success_rows / total_rows if total_rows > 0 else 0
            global_step_mean = df['step'].mean()

            # --- 2. 交集计算 (Intersection & Filtered) ---
            valid_indices = [i for i in selected_indices if i < total_rows]
            
            # 准备一个字典存储结果
            results = {key: 0.0 for key in column_mapping.keys()}
            
            if valid_indices:
                df_selected = df.iloc[valid_indices].copy()
                
                # 只有步数达到 target_step 的行才计入 error 均值
                alive_mask = df_selected['step'] >= target_step
                
                for display_name, csv_col in column_mapping.items():
                    if csv_col in df_selected.columns:
                        # 过滤掉早死的行，计算均值
                        val = df_selected.loc[alive_mask, csv_col].mean()
                        results[display_name] = val if not np.isnan(val) else 0.0
                    else:
                        results[display_name] = 0.0 # 或者可以用 None/NaN

            # --- 3. 打印结果 ---
            # 格式：[AnchorPosError, AnchorLinVel, BodyLinVel, JointVel, JointPos, SuccessRate, Step]
            output_list = [
                round(results["AnchorPosError"], 6),
                round(results["AnchorLinVel"], 6),
                round(results["BodyLinVel"], 6),
                round(results["JointVel"], 6),
                round(results["JointPos"], 6),
                f"{global_success_rate:.2%}",
                round(global_step_mean, 2)
            ]
            
            print(f"\n>>> File: {filename}")
            print(f"    Metrics List: {output_list}")
            # 同时也保留之前的详细说明，方便查看
            print(f"    Details: Global SR: {global_success_rate:.2%}, Global Step: {global_step_mean:.2f}, Intersection Size: {len(valid_indices)}")

            # --- 4. 写入文件末尾 ---
            final_means = df_selected.mean(numeric_only=True) if valid_indices else df.mean(numeric_only=True)
            final_means['step'] = global_step_mean # 强制覆盖为全局 step
            
            mean_df = pd.DataFrame([final_means])
            with open(file_path, 'a', encoding='utf-8') as f:
                f.write('\n')
                mean_df.to_csv(f, header=False, index=False, lineterminator='\n')
                f.write(f"Final Output List, {output_list}\n")
                f.write(f"Note: Step and SuccessRate are GLOBAL. Errors are INTERSECTION (alive only).\n")

        except Exception as e:
            print(f"Error processing {filename}: {e}")

